import tensorflow as tf
import pandas as pd
import numpy as np
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
from PIL import Image
import io
from sklearn.preprocessing import LabelEncoder
from tensorflow.keras.preprocessing.image import load_img, img_to_array
from tensorflow.keras.applications import ResNet50
from tensorflow.keras.layers import Dense, GlobalAveragePooling2D
from tensorflow.keras.models import Model
import uuid

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Create upload folder
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Global model and label encoder
model = None
label_encoder = LabelEncoder()
class_names = []

def create_model(num_classes):
    base_model = ResNet50(weights='imagenet', include_top=False, input_shape=(224, 224, 3))
    x = base_model.output
    x = GlobalAveragePooling2D()(x)
    x = Dense(1024, activation='relu')(x)
    predictions = Dense(num_classes, activation='softmax')(x)
    model = Model(inputs=base_model.input, outputs=predictions)
    
    for layer in base_model.layers:
        layer.trainable = False
        
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    return model

def load_and_preprocess_data(csv_path, image_folder):
    df = pd.read_csv(csv_path)
    images = []
    labels = []
    
    for _, row in df.iterrows():
        try:
            img_path = os.path.join(image_folder, row['image_name'])
            image = load_img(img_path, target_size=(224, 224))
            image_array = img_to_array(image)
            images.append(image_array)
            labels.append(row['label'])
        except Exception as e:
            print(f"Error loading image {row['image_name']}: {e}")
    
    return np.array(images), np.array(labels)

def train_model():
    global model, label_encoder, class_names
    
    # Simulate loading data from uploaded CSV
    csv_path = os.path.join(app.config['UPLOAD_FOLDER'], 'training_data.csv')
    image_folder = os.path.join(app.config['UPLOAD_FOLDER'], 'images')
    
    if not os.path.exists(csv_path) or not os.path.exists(image_folder):
        return False
    
    try:
        X, y = load_and_preprocess_data(csv_path, image_folder)
        y_encoded = label_encoder.fit_transform(y)
        y_categorical = tf.keras.utils.to_categorical(y_encoded)
        
        num_classes = len(label_encoder.classes_)
        model = create_model(num_classes)
        
        model.fit(X, y_categorical, epochs=5, batch_size=32, validation_split=0.2)
        class_names = label_encoder.classes_.tolist()
        
        return True
    except Exception as e:
        print(f"Training error: {e}")
        return False

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'csv_file' not in request.files or 'image_files' not in request.files:
        return jsonify({'error': 'Missing files'}), 400
    
    csv_file = request.files['csv_file']
    image_files = request.files.getlist('image_files')
    
    if csv_file.filename == '' or len(image_files) == 0:
        return jsonify({'error': 'No files selected'}), 400
    
    # Save CSV file
    csv_filename = secure_filename(csv_file.filename)
    csv_path = os.path.join(app.config['UPLOAD_FOLDER'], csv_filename)
    csv_file.save(csv_path)
    
    # Save image files
    image_folder = os.path.join(app.config['UPLOAD_FOLDER'], 'images')
    os.makedirs(image_folder, exist_ok=True)
    
    for image_file in image_files:
        if image_file:
            filename = secure_filename(image_file.filename)
            image_path = os.path.join(image_folder, filename)
            image_file.save(image_path)
    
    # Train model
    success = train_model()
    
    if success:
        return jsonify({'message': 'Model trained successfully', 'classes': class_names})
    else:
        return jsonify({'error': 'Training failed'}), 500

@app.route('/predict', methods=['POST'])
def predict():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    image_file = request.files['image']
    if image_file.filename == '':
        return jsonify({'error': 'No image selected'}), 400
    
    try:
        image = Image.open(io.BytesIO(image_file.read()))
        image = image.convert('RGB')
        image = image.resize((224, 224))
        image_array = img_to_array(image)
        image_array = np.expand_dims(image_array, axis=0)
        
        predictions = model.predict(image_array)
        predicted_class = np.argmax(predictions[0])
        confidence = predictions[0][predicted_class]
        
        result = {
            'predicted_class': class_names[predicted_class],
            'confidence': float(confidence),
            'all_predictions': dict(zip(class_names, predictions[0].tolist()))
        }
        
        return jsonify(result)
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/contribute', methods=['POST'])
def contribute_example():
    if 'csv_file' not in request.files or 'image_files' not in request.files:
        return jsonify({'error': 'Missing files'}), 400
    
    csv_file = request.files['csv_file']
    image_files = request.files.getlist('image_files')
    
    # Save new training data
    csv_filename = f"contribution_{uuid.uuid4().hex}.csv"
    csv_path = os.path.join(app.config['UPLOAD_FOLDER'], csv_filename)
    csv_file.save(csv_path)
    
    # Save new images
    image_folder = os.path.join(app.config['UPLOAD_FOLDER'], 'images')
    os.makedirs(image_folder, exist_ok=True)
    
    for image_file in image_files:
        if image_file:
            filename = secure_filename(image_file.filename)
            image_path = os.path.join(image_folder, filename)
            image_file.save(image_path)
    
    # Retrain model with new data
    success = train_model()
    
    if success:
        return jsonify({'message': 'New examples added and model retrained successfully'})
    else:
        return jsonify({'error': 'Retraining failed'}), 500

if __name__ == '__main__':
    app.run(debug=True)